layui.use(["util"],function(){let util=layui.util;$.ajax({url:"/timeline/listUpdateLogTimeline",method:"GET",success:function(a){if(a.request==="success"&&a.status===200){for(let i=0;i<a.data.length;i++){if(a.data[i].status!==0){let item='<li class="layui-timeline-item">                            <i class="layui-icon layui-timeline-axis">&#xe63f;</i>                            <div class="layui-timeline-content layui-text">                                <h3 class="layui-timeline-title">'+util.toDateString(a.data[i].pushDate,"yyyy-MM-dd")+"</h3>                                <p>"+a.data[i].content+"                                </p>                            </div>                        </li>";$("ul.layui-timeline").append(item)}}}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}})});